Add three tests, each with a seeded pixel so the assertion survives the fix above:

  @Test fun rotateBitmap_flipVertical_invertsRows() {
    val src = ... setPixel(0, 0) = RED
    val out = rotateBitmap(src, ExifInterface.ORIENTATION_FLIP_VERTICAL)
    assertEquals(RED, out.getPixel(0, src.height - 1))  // top row → bottom row
    assertEquals(src.width, out.width); assertEquals(src.height, out.height)
  }

  @Test fun rotateBitmap_transpose_swapsDimsAndDiagonal() {
    // TRANSPOSE = rotate90 + flipH → (x,y) → (y,x); dims swap
    val src = 4x8, setPixel(3, 0, RED)  // top-right
    val out = rotateBitmap(src, ExifInterface.ORIENTATION_TRANSPOSE)
    assertEquals(8, out.width); assertEquals(4, out.height)
    assertEquals(RED, out.getPixel(0, 3))
  }

  @Test fun rotateBitmap_transverse_swapsDimsOppositeDiagonal() {
    val src = 4x8, setPixel(0, 0, RED)
    val out = rotateBitmap(src, ExifInterface.ORIENTATION_TRANSVERSE)
    assertEquals(8, out.width); assertEquals(4, out.height)
    assertEquals(RED, out.getPixel(out.width - 1, out.height - 1))
  }

These close the branch gap and validate the specific matrix composition for each orientation.

Add two tests to ErrorLogTest.kt:

  @Test fun descriptionTruncation_cappedAt500() = runBlocking {
    errorLog.e("inference", "a".repeat(1000))
    val desc = logFile.readText().trimEnd('\n').substringAfter("ERROR [inference] ")
    assertEquals(500, desc.length)
    assertTrue(desc.all { it == 'a' })
  }

  @Test fun rotation_overSizeThreshold_renamesToLog1() = runBlocking {
    // Seed a file already past the 2 MB threshold (write raw bytes through the log dir so
    // the next e() append triggers rename). Assert errors.log.1 exists afterwards and
    // errors.log contains only the newly-appended line.
    val dir = File(context.filesDir, "logs").apply { mkdirs() }
    File(dir, "errors.log").writeBytes(ByteArray(2 * 1024 * 1024 + 1))
    errorLog.e("inference", "after-rotate")
    assertTrue(File(dir, "errors.log.1").exists())
    assertTrue(File(dir, "errors.log").readText().contains("after-rotate"))
  }

These cover the two remaining ErrorLog branches and keep future edits to bounds/rotation from shipping silently.
